<?phpDEFINE ('PRICE_VERIF_LN', 2500);DEFINE ('PRICE_VERIF_BR', 50);if ($player->pers['mail_good']<>1) {echo '<div align="center" class="but" width="90%">Подтвердите свой E-Mail адрес, <a href="/mail.php" target="_blank">подробнее</a>..</div>'; exit;}$ract = $db->sqlr('SELECT `id` FROM `watch_req_werif` WHERE `uid`='.UID.' and `date_closed`=0;', __FILE__,__LINE__,__FUNCTION__,__CLASS__);if ( isset($http->post['ver_type']) and $http->post['ver_type']>0 and $ract==false ){	$tp = ($http->post['ver_type']==2) ? 2 : 1;	$r = 1;	if ($tp==1 and $player->pers['money']>=PRICE_VERIF_LN)	{		set_vars('`money`=money-'.PRICE_VERIF_LN, UID);		$r = 0;	}	elseif ($tp==2 and $player->pers['dmoney']>=PRICE_VERIF_BR)	{		set_vars('`dmoney`=dmoney-'.PRICE_VERIF_BR, UID);		$r = 0;	}	if ($r==0)	{		$db->sql('INSERT INTO `watch_req_werif` (`uid`, `uidp`, `type`, `date`) VALUES ('.UID.', "'.pers_pack($player->pers).'", '.$tp.', '.tme().');', __FILE__,__LINE__,__FUNCTION__,__CLASS__);		say_to_chat('p','Персонаж <b>'.$player->pers['user'].'</b> подал заявку для проверки на чистоту.',0,'','*',0,'watchers'); 		$ract = 1;		echo 'Заявка добавлена!';	} else echo 'Ошибка!'; }if ($ract == false ) echo '<table width="90%" cellpadding="10" cellspacing="0" class="but"><tr><td><form method="POST" action="main.php?addon=action&do=2"><input type="hidden" name="do" value="2"><select name="ver_type" class="textBox"><option value="0">Выбрать</option><option value="1">Обычная проверка ('.PRICE_VERIF_LN.' LN)</option><option value="2">Коммерческая проверка ('.PRICE_VERIF_BR.' Бр)</option></select><input type="submit" class="textBox" value="Ок" '.(($player->pers['money']>=PRICE_VERIF_LN or $player->pers['dmoney']>=PRICE_VERIF_BR) ? '' : 'DISABLED').'></form></td></tr></table>';if ( $http->_get('read') ){	$read = $db->sqlr('SELECT `text` FROM `watch_req_werif` WHERE `uid`='.UID.' and `id`='.abs(intval($http->get['read'])).';', __FILE__,__LINE__,__FUNCTION__,__CLASS__);	$read = !empty($read) ? $read : 'Дело отсутствует!';	echo '<div class="inv_button">'.$read.'</div>';}$res = $db->sql('SELECT * FROM `watch_req_werif` WHERE `uid`='.UID.' ORDER BY `date` DESC;', __FILE__,__LINE__,__FUNCTION__,__CLASS__);echo '<table width="90%" border="1" cellspacing="0" cellpadding="0" class="but">';while ( $rs = $db->fetchAssoc($res) ){		switch ($rs['type'])		{			case 1: $color = '#FFDDDD';$tt = 'Обычная'; break;			case 2: $color = '#DDAAAA';$tt = 'Коммерческая'; break;		}				echo "<tr>";		echo "<td bgcolor=".$color." class=timef>&nbsp;".date("d.m.y H:i:s", $rs['date'])."&nbsp;</td>";		echo "<td class=items>&nbsp;".$tt."&nbsp;</td>";		if ($rs['whoid']>0)		{			$p = explode('|', $rs['who']);			echo "<td class=user>&nbsp;".(($p[2]!='none') ? '<img src=http://'.IMG.'/signs/'.$p[2].'.gif>' : '').$p[0]."[".$p[1]."] <a href='info.php?".$p[0]."' target=_blank><img src=http://".IMG."/i.gif></a>&nbsp;</td>";		}		if ( $rs['date_closed']>0 )		{			echo '<td class=timef onClick="location=\'main.php?addon=action&do=2&read='.$rs['id'].'\';">&nbsp;'.(($rs['result']==1) ? '<span class="inv_green">Проверка пройдена</span>' : '<span class="inv_red">Проверка не пройдена</span>').'&nbsp;</td>';			echo "<td class=return_win>&nbsp;".date("d.m.y H:i:s", $rs['date_closed'])."&nbsp;</td>";		} else echo "<td class=timef>&nbsp;Идёт обработка, подождите&nbsp;</td>";		echo "</tr>";}echo '</table>';?>